+  ASSERT_NE(crw, nullptr);
+
+  auto carr = absl::make_unique<
+      grpc::testing::MockClientAsyncResponseReader<EchoResponse>>();
+  ASSERT_NE(carr, nullptr);
+
+  auto car =
